import React from 'react';
import Menu from './Menu'; // Assuming Menu.js is your main menu component
import logo from '/Users/noorhatem/Desktop/uni/semester 6/service oriented computing/quickbite/client/src/images/logo.png'; 
import { Box, CssBaseline } from '@mui/material';

function App() {
  return (
    <Box
      display="flex"
      flexDirection="column"
      minHeight="100vh"
      style={{ backgroundColor: '#f1f1f1' }} // light gray background
    >
      <CssBaseline />

      {/* Header with the logo */}
      <Box
        display="flex"
        justifyContent="flex-start" // Align logo to the left
        alignItems="center"
        height="80px"
        backgroundColor="#004c97" // blue background to match branding
        paddingLeft="20px" // Add some space from the left edge
      >
        <img
          src={logo}
          alt="QuickBite logo"
          style={{
            width: '100px', // Adjust the size of the logo
            height: 'auto',
          }}
        />
      </Box>

      <Menu />

      {/* Footer */}
      <footer
        style={{
          marginTop: 'auto',
          padding: '20px',
          backgroundColor: '#f1f1f1',
          textAlign: 'center',
        }}
      >
        <p>© 2025 QuickBite. All rights reserved.</p>
      </footer>
    </Box>
  );
}

export default App;
